package org.apache.commons.math.optimization.linear;

import org.junit.Assert;
import org.junit.Test;
import org.apache.commons.math.optimization.GoalType;
import org.apache.commons.math.optimization.RealPointValuePair;
import org.apache.commons.math.util.Precision;
import java.util.ArrayList;

public class Reproduction {
    @Test
    public void testMath713NegativeVariable() {
        LinearObjectiveFunction f = new LinearObjectiveFunction(new double[] {1.0, 1.0}, 0.0d);
        ArrayList<LinearConstraint> constraints = new ArrayList<LinearConstraint>();
        constraints.add(new LinearConstraint(new double[] {1, 0}, Relationship.EQ, 1));

        double epsilon = 1e-6;
        SimplexSolver solver = new SimplexSolver();
        RealPointValuePair solution = solver.optimize(f, constraints, GoalType.MINIMIZE, true);

        System.out.println("x0: " + solution.getPoint()[0]);
        System.out.println("x1: " + solution.getPoint()[1]);
        System.out.println("Epsilon: " + epsilon);
        System.out.println("CompareTo x0: " + Precision.compareTo(solution.getPoint()[0], 0.0d, epsilon));
        System.out.println("CompareTo x1: " + Precision.compareTo(solution.getPoint()[1], 0.0d, epsilon));

        Assert.assertTrue("x0 should be non-negative", Precision.compareTo(solution.getPoint()[0], 0.0d, epsilon) >= 0);
        Assert.assertTrue("x1 should be non-negative", Precision.compareTo(solution.getPoint()[1], 0.0d, epsilon) >= 0);
    }
}
